import{_ as a,o as t,c as p,ag as n}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung007.jpg",u="/images/uebung008.jpg",g=JSON.parse('{"title":"Übung Lektion 8","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung08.md","filePath":"lektionen/uebung08.md"}'),i={name:"lektionen/uebung08.md"};function o(s,e,h,q,d,m){return t(),p("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-8" tabindex="-1">Übung Lektion 8 <a class="header-anchor" href="#ubung-lektion-8" aria-label="Permalink to &quot;Übung Lektion 8&quot;">​</a></h1><p>A) Erklären Sie die folgenden Nomina durch Angabe der Wurzel, von der abgeleitet wurde, und des Nominalsuffixes. Geben Sie Geschlecht und Bedeutung an:</p><p>1. lobha</p><p>lubh 4 P &quot;begehren&quot; + -a m.: &quot;Begierde&quot;</p><p>2. rakṣa</p><p>rakṣ 1 P &quot;hüten&quot; + -a 3: &quot;hütend, beschützend&quot; ; m.: &quot;Wächter&quot;</p><p>3. śrotra</p><p>śru 5 P &quot;hören&quot; + -tra n.: &quot;Ohr&quot;</p><p>4. mati</p><p>man 4 Ā &quot;denken&quot; + -ti f.: &quot;Gedanke, Meinung&quot;</p><p>5. savana</p><p>su 5 U &quot;auspressen&quot; + -ana n.: &quot;Somapressung&quot;</p><p>6. yodha</p><p>yudh 4 Ā &quot;kämpfen&quot; + -a m.: &quot;Kämpfer, Soldat&quot;</p><p>7. lābha</p><p>labh 1 Ā &quot;erhalten&quot; + -a m.: &quot;Bekommen, Gewinn&quot;</p><p>8. kāraṇa</p><p>kṛ 8 U &quot;machen, tun&quot; + -ana n.: &quot;Ursache, Grund&quot;</p><p>9. gati</p><p>gam 1 P &quot;gehen&quot; + -ti f.: &quot;Gang, &#39;Laufbahn&#39;, Ziel&quot;</p><p>10. khādana</p><p>khād 1 P &quot;kauen&quot; + -ana n.: &quot;Kauen, Verzehr, Futter&quot;</p><p>11. smara</p><p>smṛ 1 P &quot;vergegenwärtigen&quot; + -a m.: &quot;Erinnerung, Gedächtnis, Sehnsucht, Liebe&quot;</p><p>12. sṛṣṭi</p><p>sṛj 6 P / 4 A &quot;emanieren lassen, erschaffen&quot; + -ti: &quot;Emanation, Schöpfung&quot;</p><p>13. tantra</p><p>tan 8 U &quot;aufspannen&quot; + -tra n.: &quot;Webkette, Gewebe&quot;</p><p>14. bhāva</p><p>bhū 1 P &quot;werden, sein&quot; + -a m.: &quot;Werden, natur, Charakter&quot;</p><p>15. darśana</p><p>dṛś (4 P: paśyati) &quot;sehen&quot; + -ana n-: &quot;Sehen, Erscheinung, Sichtweise, philosophisches System&quot;</p><p>16. netra</p><p>nī 1 U &quot;führen&quot; + -tra n.: &quot;Auge&quot;</p><p>17. veśana</p><p>viś 6 P &quot;eintreten&quot; + -ana n.: &quot;Eintritt&quot;</p><p>18. kopa</p><p>kup 4 P &quot;zürnen&quot; + -a m.: &quot;Zorn&quot;</p><p>19. sarga</p><p>ṛj 6 P / 4 A &quot;emanieren lassen, erschaffen&quot; + -a m.: &quot;Loslassen, Emanation, Schöpfung&quot;</p><p>20. yajana</p><p>yaj 1 U &quot;opfern&quot; + -ana n.: &quot;Opfern, Opferplatz&quot;</p><p>21. moha</p><p>muḥ 4 P &quot;verwirrt sein&quot; + -a m.: &quot;Verwirrtsein, Verblendung, Irrtum&quot;</p><p>22. śrava</p><p>śru 5 P &quot;hören&quot; + -a m.: &quot;Hören&quot;</p><p>23. bhavana</p><p>bhū 1 P &quot;werden, sein&quot; + -ana n.: &quot;Werden, Entstehen, Entstehung&quot;</p><p>24. nīti</p><p>nī 1 U &quot;führen&quot; + -ti f.: &quot;Führung&quot;</p><p>25. nartana</p><p>nṛt 4 P &quot;tanzen&quot; + -ana 3: &quot;tanzend, Tänzer&quot; ; n.: &quot;Tanz&quot;</p><p>26. jaya</p><p>ji 1 P &quot;siegen&quot; + -a m.: &quot;Siegen, Sieg&quot;</p><p>27. nayana</p><p>nī 1 U &quot;führen&quot; + -ana n.: &quot;Auge&quot;</p><p>28. śravaṇa</p><p>śru 5 P &quot;hören&quot; + -ana n.: &quot;Ohr&quot;</p><p>B) Bilden Sie Abstrakta zu allen bisher gelernten Nomina und überlegen Sie deren Bedeutung (mündlich)</p><p>C) Setzen Sie als direktes Objekt im Singular und Plural ein:</p><p>kṣatriyas ... rakṣati (brāhmaṇa, vaiśya, śūdra, brāhmaṇī, kṣatriyā)</p><p>kṣatriyo brāhmaṇaṃ / brāhmaṇān / vaiśyaṃ / vaiśyān rakṣati. kṣatriyaḥ śūdraṃ / śūdrān. kṣatriyo brāhmaṇīṃ / brāhmaṇī rakṣati. kṣatriyaḥ kṣatriyāṃ / kṣatriyā rakṣati.</p><p>क्षत्रियो ब्राह्मणं रक्षति । क्षत्रियो ब्राह्मणान्रक्षति । क्त्रियो वैश्यं रक्षति । क्षत्रियो वैश्यान्रक्षति । क्षत्रियः शूद्रं रक्षति । क्षत्रियः शूद्रान्रक्षति । क्षत्रियो ब्राह्मणीं रक्षति । क्षत्रियो ब्राह्मणी रक्षति । क्षत्रियः क्षत्रियां रक्षति । क्षत्रियः क्षत्रिया रक्षति ॥</p><p>D) Übersetzen Sie</p><p>1. Kṣatriyas behüten sowohl Brahmanen als auch Vaiśyas und Śūdras. (2 Möglichkeiten)</p><p>kṣatriyā brāhmaṇāṃś ca vaiśyāṃś ca śūdrāṃś ca rakṣanti / kṣatriyā brāhmaṇavaiśyaśūdrān rakṣanti.</p><p>क्षत्रिया ब्राह्मणांश्च वैश्यांश्च शूद्रांश्च रक्षन्ति । क्षत्रिया ब्राह्मणवैश्यशूद्रान्रक्षन्ति ।</p><p>2. Ein heiliger Mann sieht sowohl Himmel als auch Höllen.</p><p>sādhuḥ svargāmś ca narakāmś ca paśyati.</p><p>साधुः स्वर्गांश्च नरकांश्च पश्यति ।</p><p>3. Er besiegt Kṣatriyas.</p><p>kṣatriyāñ jayati.</p><p>क्षत्रियञ्जयति ।</p><p>4. Sie spannt die Webkette auf.</p><p>tantraṃ tanoti.</p><p>तन्त्रं तनोति ।</p><p>5. Soldaten kämpfen.</p><p>yodhā yudhyante.</p><p>योधा युध्यन्ते ।</p><p>6. Der Brahmane macht ein Feuer.</p><p>brāhmaṇo &#39;gniṃ karoti.</p><p>ब्राह्मणो ऽग्निं करोति ।</p><p>7. Brahmanen machen Feuer.</p><p>brāhmaṇā agniṃ kurvanti.</p><p>ब्राह्मणा अग्निं कुर्वन्ति ।</p><p>8. Was tun diese Kämpfer?</p><p>ime yodhāḥ kiṃ kurvanti?</p><p>इमे योधाः किं कुर्वन्ति ।</p><p>9. Wen sieht das Auge?</p><p>netraṃ (nayanaṃ) kaṃ paśyati?</p><p>नेत्रं (नयनं) कं पश्यति ।</p><p>10. Was begehren Götter?</p><p>devāḥ kiṃ lubhyanti?</p><p>देवाः किं लुभ्यन्ति ।</p><p>11. Was ist der Grund?</p><p>kiṃ kāraṇam?</p><p>किं कारणम् ॥</p><p><img src="'+r+'" alt=""><br> ime yodhāḥ kiṃ kurvanti? = इमे योधाः किं कुर्वन्ति ।<br> Schlacht auf dem Kurukṣetra (कुरुक्षेत्र) in einem alten Mahābhārata-Manuskript<br> [Bildquelle: Wikipedia. Public domain]</p><p>1. शूद्रो बालं नयति |</p><p>Der Śūdra führt den Knaben.</p><p>2. कविर्देवं यजते |</p><p>Der Dichter opfert dem Gott.</p><p>3. साधुः फलानि खादति |</p><p>Der Heilige isst Früchte.</p><p>4. गुरुः क्रोधं जयति |</p><p>Der Meister besiegt seinen Zorn.</p><p>5. देवो नरकं सृजति |</p><p>Der Gott erschafft die Hölle.</p><p>6. धेनुर्ग्रामं विशति |</p><p>Die Kuh betritt das Dorf.</p><p>7. कामक्रोधलोभा नरकं नयन्ति |</p><p>Leidenschaft, Zorn und Gier führen zur Hölle.</p><p>8. देवतां यजति |</p><p>Er opfert für einen Opferherren der Gottheit.</p><p>9. बाला भवति |</p><p>Ein Mädchen entsteht.</p><p>10. सारथी रथं नयति |</p><p>Ein Wagenlenker lenkt den Wagen.</p><p>11. कपयः फलानि खादन्ति |</p><p>Die Affen fressen die Früchte.</p><p>12. बाला लिखति |</p><p>Das Mädchen scheibt bzw. zeichnet.</p><p>13. कुमारी गृहं विशति |</p><p>Die Jungfrau betritt das Haus.</p><p>14. देवो नागं सृजति |</p><p>Gott schafft den Elefanten bzw. die Schlange bzw. den Nāga.</p><p>15. बालो गजं नयति |</p><p>Der Knabe führt den Elefanten.</p><p>16. विमला शोचति | (विमला  Eigenname Vimalā)</p><p>Vimalā ist traurig.</p><p>17. शुकः पतति |</p><p>Der Papagei fliegt.</p><p>18. बालः पत्रिकां लिखति |</p><p>Der Knabe schreibt einen Brief.</p><p><img src="'+u+'" alt=""><br> Abb.: kapiḥ phalaṃ khādati = कपिः फलं खदति<br> Rhesusaffe (<em>Macaca mulatta</em>), Agra (आगरा)<br> [Bildquelle: kandyjaxx. -- <a href="http://www.flickr.com/photos/kandyjaxx/2294858779/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/kandyjaxx/2294858779/</a>. -- Zugriff am 2008-11-28. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzelle Nutzung, keine Bearbeitung)]</p>',136)])])}const k=a(i,[["render",o]]);export{g as __pageData,k as default};
